    21|export function actorMiddleware(db: Db, opts: ActorMiddlewareOptions): RequestHandler {
    22|  const boardAuth = boardAuthService(db);
    23|  return async (req, _res, next) => {
    24|    req.actor =
    25|      opts.deploymentMode === "local_trusted"
    26|        ? { type: "board", userId: "local-board", isInstanceAdmin: true, source: "local_implicit" }
    27|        : { type: "none", source: "none" };
