    32|    if (!authHeader?.toLowerCase().startsWith("bearer ")) {
    33|      if (opts.deploymentMode === "authenticated" && opts.resolveSession) {
    34|        let session: BetterAuthSessionResult | null = null;
    35|        try {
    36|          session = await opts.resolveSession(req);
    37|        } catch (err) {
    38|          logger.warn(
    39|            { err, method: req.method, url: req.originalUrl },
    40|            "Failed to resolve auth session from request headers",
    41|          );
    42|        }
    43|        if (session?.user?.id) {
    44|          const userId = session.user.id;
    45|          const [roleRow, memberships] = await Promise.all([
    46|            db
    47|              .select({ id: instanceUserRoles.id })
    48|              .from(instanceUserRoles)
    49|              .where(and(eq(instanceUserRoles.userId, userId), eq(instanceUserRoles.role, "instance_admin")))
    50|              .then((rows) => rows[0] ?? null),
    51|            db
    52|              .select({ companyId: companyMemberships.companyId })
    53|              .from(companyMemberships)
    54|              .where(
    55|                and(
    56|                  eq(companyMemberships.principalType, "user"),
    57|                  eq(companyMemberships.principalId, userId),
    58|                  eq(companyMemberships.status, "active"),
    59|                ),
    60|              ),
    61|          ]);
    62|          req.actor = {
    63|            type: "board",
    64|            userId,
    65|            companyIds: memberships.map((row) => row.companyId),
    66|            isInstanceAdmin: Boolean(roleRow),
    67|            runId: runIdHeader ?? undefined,
    68|            source: "session",
    69|          };
    70|          next();
    71|          return;
    72|        }
    73|      }
    74|      if (runIdHeader) req.actor.runId = runIdHeader;
    75|      next();
    76|      return;
    77|    }
    78|
    79|    const token = authHeader.slice("bearer ".length).trim();
