    93|          companyIds: access.companyIds,
    94|          isInstanceAdmin: access.isInstanceAdmin,
    95|          keyId: boardKey.id,
    96|          runId: runIdHeader || undefined,
    97|          source: "board_key",
    98|        };
    99|        next();
