   136|        agentId: claims.sub,
   137|        companyId: claims.company_id,
   138|        keyId: undefined,
   139|        runId: runIdHeader || claims.run_id || undefined,
   140|        source: "agent_jwt",
   141|      };
   142|      next();
   143|      return;
   144|    }
