   147|      .update(agentApiKeys)
   148|      .set({ lastUsedAt: new Date() })
   149|      .where(eq(agentApiKeys.id, key.id));
   150|
   151|    const agentRecord = await db
   152|      .select()
   153|      .from(agents)
   154|      .where(eq(agents.id, key.agentId))
   155|      .then((rows) => rows[0] ?? null);
   156|
   157|    if (!agentRecord || agentRecord.status === "terminated" || agentRecord.status === "pending_approval") {
   158|      next();
   159|      return;
   160|    }
   161|
   162|    req.actor = {
   163|      type: "agent",
   164|      agentId: key.agentId,
   165|      companyId: key.companyId,
   166|      keyId: key.id,
   167|      runId: runIdHeader || undefined,
   168|      source: "agent_key",
   169|    };
   170|
