     9|
    10|function buildDismissedAtByKey(
    11|  dismissals: Array<{ itemKey: string; dismissedAt: Date | string }>,
    12|): Map<string, number> {
    13|  return new Map(
    14|    dismissals.map((dismissal) => [dismissal.itemKey, new Date(dismissal.dismissedAt).getTime()]),
    15|  );
