    23|
    24|  router.get("/companies/:companyId/sidebar-badges", async (req, res) => {
    25|    const companyId = req.params.companyId as string;
    26|    assertCompanyAccess(req, companyId);
    27|    let canApproveJoins = false;
    28|    if (req.actor.type === "board") {
    29|      canApproveJoins =
    30|        req.actor.source === "local_implicit" ||
    31|        Boolean(req.actor.isInstanceAdmin) ||
    32|        (await access.canUser(companyId, req.actor.userId, "joins:approve"));
    33|    } else if (req.actor.type === "agent" && req.actor.agentId) {
    34|      canApproveJoins = await access.hasPermission(companyId, "agent", req.actor.agentId, "joins:approve");
    35|    }
    36|
    37|    const visibleJoinRequests = canApproveJoins
    38|      ? await db
    39|        .select({
    40|          id: joinRequests.id,
    41|          updatedAt: joinRequests.updatedAt,
    42|          createdAt: joinRequests.createdAt,
    43|        })
    44|        .from(joinRequests)
    45|        .where(and(eq(joinRequests.companyId, companyId), eq(joinRequests.status, "pending_approval")))
    46|      : [];
    47|
    48|    const dismissedAtByKey =
    49|      req.actor.type === "board" && req.actor.userId
    50|        ? await db
    51|          .select({ itemKey: inboxDismissals.itemKey, dismissedAt: inboxDismissals.dismissedAt })
    52|          .from(inboxDismissals)
    53|          .where(and(eq(inboxDismissals.companyId, companyId), eq(inboxDismissals.userId, req.actor.userId)))
    54|          .then(buildDismissedAtByKey)
    55|        : new Map<string, number>();
    56|
    57|    const badges = await svc.get(companyId, {
    58|      dismissals: dismissedAtByKey,
    59|      joinRequests: visibleJoinRequests,
    60|    });
    61|    const summary = await dashboard.summary(companyId);
    62|    const hasFailedRuns = badges.failedRuns > 0;
    63|    const alertsCount =
    64|      (summary.agents.error > 0 && !hasFailedRuns ? 1 : 0) +
    65|      (summary.costs.monthBudgetCents > 0 && summary.costs.monthUtilizationPercent >= 80 ? 1 : 0);
    66|    badges.inbox = badges.failedRuns + alertsCount + badges.joinRequests + badges.approvals;
    67|
    68|    res.json(badges);
