    21|function sanitizeSvgBuffer(input: Buffer): Buffer | null {
    22|  const raw = input.toString("utf8").trim();
    23|  if (!raw) return null;
    24|
    25|  const baseDom = new JSDOM("");
    26|  const domPurify = createDOMPurify(
    27|    baseDom.window as unknown as Parameters<typeof createDOMPurify>[0],
    28|  );
    29|  domPurify.addHook("uponSanitizeAttribute", (_node, data) => {
    30|    const attrName = data.attrName.toLowerCase();
    31|    const attrValue = (data.attrValue ?? "").trim();
    32|
    33|    if (attrName.startsWith("on")) {
    34|      data.keepAttr = false;
    35|      return;
    36|    }
    37|
    38|    if ((attrName === "href" || attrName === "xlink:href") && attrValue && !attrValue.startsWith("#")) {
    39|      data.keepAttr = false;
    40|    }
    41|  });
    42|
    43|  let parsedDom: JSDOM | null = null;
    44|  try {
    45|    const sanitized = domPurify.sanitize(raw, {
    46|      USE_PROFILES: { svg: true, svgFilters: true, html: false },
    47|      FORBID_TAGS: ["script", "foreignObject"],
    48|      FORBID_CONTENTS: ["script", "foreignObject"],
    49|      RETURN_TRUSTED_TYPE: false,
    50|    });
