    54|    const root = document.documentElement;
    55|    if (!root || root.tagName.toLowerCase() !== "svg") return null;
    56|
    57|    for (const el of Array.from(root.querySelectorAll("script, foreignObject"))) {
    58|      el.remove();
    59|    }
    60|    for (const el of Array.from(root.querySelectorAll("*"))) {
    61|      for (const attr of Array.from(el.attributes)) {
    62|        const attrName = attr.name.toLowerCase();
    63|        const attrValue = attr.value.trim();
    64|        if (attrName.startsWith("on")) {
