   152|/**
   153| * Resolve a plugin by either database ID or plugin key.
   154| *
   155| * Lookup order:
   156| * - UUID-like IDs: getById first, then getByKey.
   157| * - Scoped package keys (e.g. "@scope/name"): getByKey only, never getById.
   158| * - Other non-UUID IDs: try getById first (test/memory registries may allow this),
   159| *   then fallback to getByKey. Any UUID parse error from getById is ignored.
   160| *
   161| * @param registry - The plugin registry service instance
   162| * @param pluginId - Either a database UUID or plugin key (manifest id)
   163| * @returns Plugin record or null if not found
   164| */
   165|async function resolvePlugin(
   166|  registry: ReturnType<typeof pluginRegistryService>,
   167|  pluginId: string,
   168|) {
   169|  const isUuid = UUID_REGEX.test(pluginId);
   170|  const isScopedPackageKey = pluginId.startsWith("@") || pluginId.includes("/");
   171|
   172|  // Scoped package IDs are valid plugin keys but invalid UUIDs.
   173|  // Skip getById() entirely to avoid Postgres uuid parse errors.
   174|  if (isScopedPackageKey && !isUuid) {
   175|    return registry.getByKey(pluginId);
   176|  }
   177|
   178|  try {
   179|    const byId = await registry.getById(pluginId);
   180|    if (byId) return byId;
   181|  } catch (error) {
   182|    const maybeCode =
   183|      typeof error === "object" && error !== null && "code" in error
   184|        ? (error as { code?: unknown }).code
   185|        : undefined;
   186|    // Ignore invalid UUID cast errors and continue with key lookup.
   187|    if (maybeCode !== "22P02") {
   188|      throw error;
   189|    }
   190|  }
   191|
   192|  return registry.getByKey(pluginId);
   193|}
