     2|
     3|const SAFE_METHODS = new Set(["GET", "HEAD", "OPTIONS"]);
     4|const DEFAULT_DEV_ORIGINS = [
     5|  "http://localhost:3100",
     6|  "http://127.0.0.1:3100",
     7|];
     8|
     9|function parseOrigin(value: string | undefined) {
    10|  if (!value) return null;
    11|  try {
    12|    const url = new URL(value);
    13|    return `${url.protocol}//${url.host}`.toLowerCase();
    14|  } catch {
    15|    return null;
    16|  }
    17|}
    18|
    19|function trustedOriginsForRequest(req: Request) {
    20|  const origins = new Set(DEFAULT_DEV_ORIGINS.map((value) => value.toLowerCase()));
    21|  const forwardedHost = req.header("x-forwarded-host")?.split(",")[0]?.trim();
    22|  const host = forwardedHost || req.header("host")?.trim();
    23|  if (host) {
    24|    origins.add(`http://${host}`.toLowerCase());
    25|    origins.add(`https://${host}`.toLowerCase());
    26|  }
    27|  return origins;
    28|}
    29|
    30|function isTrustedBoardMutationRequest(req: Request) {
    31|  const allowedOrigins = trustedOriginsForRequest(req);
    32|  const origin = parseOrigin(req.header("origin"));
    33|  if (origin && allowedOrigins.has(origin)) return true;
    34|
    35|  const refererOrigin = parseOrigin(req.header("referer"));
    36|  if (refererOrigin && allowedOrigins.has(refererOrigin)) return true;
    37|
    38|  return false;
    39|}
    40|
    41|export function boardMutationGuard(): RequestHandler {
    42|  return (req, res, next) => {
    43|    if (SAFE_METHODS.has(req.method.toUpperCase())) {
    44|      next();
    45|      return;
    46|    }
    47|
    48|    if (req.actor.type !== "board") {
    49|      next();
    50|      return;
    51|    }
    52|
    53|    // Local-trusted mode and board bearer keys are not browser-session requests.
    54|    // In these modes, origin/referer headers can be absent; do not block those mutations.
    55|    if (req.actor.source === "local_implicit" || req.actor.source === "board_key") {
    56|      next();
    57|      return;
    58|    }
    59|
    60|    if (!isTrustedBoardMutationRequest(req)) {
    61|      res.status(403).json({ error: "Board mutation requires trusted browser origin" });
    62|      return;
    63|    }
    64|
    65|    next();
    66|  };
    67|}
