     2|import { ZodError } from "zod";
     3|import { HttpError } from "../errors.js";
     4|import { trackErrorHandlerCrash } from "@paperclipai/shared/telemetry";
     5|import { getTelemetryClient } from "../telemetry.js";
     6|
     7|export interface ErrorContext {
     8|  error: { message: string; stack?: string; name?: string; details?: unknown; raw?: unknown };
     9|  method: string;
    10|  url: string;
    11|  reqBody?: unknown;
    12|  reqParams?: unknown;
    13|  reqQuery?: unknown;
    14|}
    15|
    16|function attachErrorContext(
    17|  req: Request,
    18|  res: Response,
    19|  payload: ErrorContext["error"],
    20|  rawError?: Error,
    21|) {
    22|  (res as any).__errorContext = {
    23|    error: payload,
    24|    method: req.method,
    25|    url: req.originalUrl,
    26|    reqBody: req.body,
    27|    reqParams: req.params,
    28|    reqQuery: req.query,
    29|  } satisfies ErrorContext;
    30|  if (rawError) {
    31|    (res as any).err = rawError;
    32|  }
    33|}
    34|
    35|export function errorHandler(
    36|  err: unknown,
    37|  req: Request,
    38|  res: Response,
    39|  _next: NextFunction,
    40|) {
    41|  if (err instanceof HttpError) {
    42|    if (err.status >= 500) {
    43|      attachErrorContext(
    44|        req,
    45|        res,
    46|        { message: err.message, stack: err.stack, name: err.name, details: err.details },
    47|        err,
    48|      );
    49|      const tc = getTelemetryClient();
    50|      if (tc) trackErrorHandlerCrash(tc, { errorCode: err.name });
    51|    }
    52|    res.status(err.status).json({
    53|      error: err.message,
    54|      ...(err.details ? { details: err.details } : {}),
    55|    });
    56|    return;
    57|  }
    58|
    59|  if (err instanceof ZodError) {
    60|    res.status(400).json({ error: "Validation error", details: err.errors });
    61|    return;
    62|  }
    63|
    64|  const rootError = err instanceof Error ? err : new Error(String(err));
    65|  attachErrorContext(
    66|    req,
    67|    res,
    68|    err instanceof Error
    69|      ? { message: err.message, stack: err.stack, name: err.name }
    70|      : { message: String(err), raw: err, stack: rootError.stack, name: rootError.name },
    71|    rootError,
    72|  );
    73|
    74|  const tc = getTelemetryClient();
    75|  if (tc) trackErrorHandlerCrash(tc, { errorCode: rootError.name });
    76|
    77|  res.status(500).json({ error: "Internal server error" });
    78|}
