    31|export function resolvePrivateHostnameAllowSet(opts: { allowedHostnames: string[]; bindHost: string }): Set<string> {
    32|  const configuredAllow = normalizeAllowedHostnames(opts.allowedHostnames);
    33|  const bindHost = opts.bindHost.trim().toLowerCase();
    34|  const allowSet = new Set<string>(configuredAllow);
    35|
    36|  if (bindHost && bindHost !== "0.0.0.0") {
    37|    allowSet.add(bindHost);
    38|  }
    39|  allowSet.add("localhost");
    40|  allowSet.add("127.0.0.1");
    41|  allowSet.add("::1");
    42|  return allowSet;
