    44|
    45|function blockedHostnameMessage(hostname: string): string {
    46|  return (
    47|    `Hostname '${hostname}' is not allowed for this Paperclip instance. ` +
    48|    `If you want to allow this hostname, please run pnpm paperclipai allowed-hostname ${hostname}`
    49|  );
    50|}
    51|
    52|export function privateHostnameGuard(opts: {
    53|  enabled: boolean;
    54|  allowedHostnames: string[];
    55|  bindHost: string;
    56|}): RequestHandler {
    57|  if (!opts.enabled) {
    58|    return (_req, _res, next) => next();
    59|  }
    60|
    61|  const allowSet = resolvePrivateHostnameAllowSet({
    62|    allowedHostnames: opts.allowedHostnames,
    63|    bindHost: opts.bindHost,
    64|  });
    65|
    66|  return (req, res, next) => {
    67|    const hostname = extractHostname(req);
    68|    const wantsJson = req.path.startsWith("/api") || req.accepts(["json", "html", "text"]) === "json";
    69|
    70|    if (!hostname) {
    71|      const error = "Missing Host header. If you want to allow a hostname, run pnpm paperclipai allowed-hostname <host>.";
    72|      if (wantsJson) {
    73|        res.status(403).json({ error });
    74|      } else {
    75|        res.status(403).type("text/plain").send(error);
    76|      }
    77|      return;
    78|    }
    79|
    80|    if (isLoopbackHostname(hostname) || allowSet.has(hostname)) {
    81|      next();
    82|      return;
    83|    }
    84|
    85|    const error = blockedHostnameMessage(hostname);
    86|    if (wantsJson) {
    87|      res.status(403).json({ error });
    88|    } else {
    89|      res.status(403).type("text/plain").send(error);
    90|    }
    91|  };
