     8|  authAccounts,
     9|  authSessions,
    10|  authUsers,
    11|  authVerifications,
    12|} from "@paperclipai/db";
    13|import type { Config } from "../config.js";
    14|
    15|export type BetterAuthSessionUser = {
    16|  id: string;
    17|  email?: string | null;
    18|  name?: string | null;
    19|};
    20|
    21|export type BetterAuthSessionResult = {
    22|  session: { id: string; userId: string } | null;
    23|  user: BetterAuthSessionUser | null;
    24|};
    25|
    26|type BetterAuthInstance = ReturnType<typeof betterAuth>;
    27|
    28|function headersFromNodeHeaders(rawHeaders: IncomingHttpHeaders): Headers {
    29|  const headers = new Headers();
    30|  for (const [key, raw] of Object.entries(rawHeaders)) {
    31|    if (!raw) continue;
    32|    if (Array.isArray(raw)) {
    33|      for (const value of raw) headers.append(key, value);
    34|      continue;
    35|    }
    36|    headers.set(key, raw);
    37|  }
    38|  return headers;
    39|}
    40|
    41|function headersFromExpressRequest(req: Request): Headers {
    42|  return headersFromNodeHeaders(req.headers);
    43|}
    44|
    45|export function deriveAuthTrustedOrigins(config: Config): string[] {
    46|  const baseUrl = config.authBaseUrlMode === "explicit" ? config.authPublicBaseUrl : undefined;
    47|  const trustedOrigins = new Set<string>();
    48|
    49|  if (baseUrl) {
    50|    try {
    51|      trustedOrigins.add(new URL(baseUrl).origin);
    52|    } catch {
    53|      // Better Auth will surface invalid base URL separately.
    54|    }
    55|  }
    56|  if (config.deploymentMode === "authenticated") {
    57|    for (const hostname of config.allowedHostnames) {
    58|      const trimmed = hostname.trim().toLowerCase();
    59|      if (!trimmed) continue;
    60|      trustedOrigins.add(`https://${trimmed}`);
    61|      trustedOrigins.add(`http://${trimmed}`);
    62|    }
    63|  }
    64|
    65|  return Array.from(trustedOrigins);
    66|}
    67|
    68|export function createBetterAuthInstance(db: Db, config: Config, trustedOrigins?: string[]): BetterAuthInstance {
    69|  const baseUrl = config.authBaseUrlMode === "explicit" ? config.authPublicBaseUrl : undefined;
    70|  const secret = process.env.BETTER_AUTH_SECRET ?? process.env.PAPERCLIP_AGENT_JWT_SECRET;
    71|  if (!secret) {
    72|    throw new Error(
    73|      "BETTER_AUTH_SECRET (or PAPERCLIP_AGENT_JWT_SECRET) must be set. " +
    74|      "For local development, set BETTER_AUTH_SECRET=paperc...cret in your .env file.",
    75|    );
    76|  }
    77|  const effectiveTrustedOrigins = trustedOrigins ?? deriveAuthTrustedOrigins(config);
    78|
    79|  const publicUrl = process.env.PAPERCLIP_PUBLIC_URL ?? baseUrl;
    80|  const isHttpOnly = publicUrl ? publicUrl.startsWith("http://") : false;
    81|
    82|  const authConfig = {
    83|    baseURL: baseUrl,
    84|    secret,
    85|    trustedOrigins: effectiveTrustedOrigins,
    86|    database: drizzleAdapter(db, {
    87|      provider: "pg",
    88|      schema: {
    89|        user: authUsers,
    90|        session: authSessions,
    91|        account: authAccounts,
    92|        verification: authVerifications,
    93|      },
    94|    }),
    95|    emailAndPassword: {
    96|      enabled: true,
    97|      requireEmailVerification: false,
    98|      disableSignUp: config.authDisableSignUp,
    99|    },
   100|    ...(isHttpOnly ? { advanced: { useSecureCookies: false } } : {}),
   101|  };
   102|
   103|  if (!baseUrl) {
   104|    delete (authConfig as { baseURL?: string }).baseURL;
   105|  }
   106|
   107|  return betterAuth(authConfig);
   108|}
   109|
   110|export function createBetterAuthHandler(auth: BetterAuthInstance): RequestHandler {
   111|  const handler = toNodeHandler(auth);
   112|  return (req, res, next) => {
   113|    void Promise.resolve(handler(req, res)).catch(next);
   114|  };
   115|}
   116|
   117|export async function resolveBetterAuthSessionFromHeaders(
   118|  auth: BetterAuthInstance,
   119|  headers: Headers,
   120|): Promise<BetterAuthSessionResult | null> {
   121|  const api = (auth as unknown as { api?: { getSession?: (input: unknown) => Promise<unknown> } }).api;
   122|  if (!api?.getSession) return null;
   123|
   124|  const sessionValue = await api.getSession({
   125|    headers,
   126|  });
   127|  if (!sessionValue || typeof sessionValue !== "object") return null;
   128|
   129|  const value = sessionValue as {
   130|    session?: { id?: string; userId?: string } | null;
   131|    user?: { id?: string; email?: string | null; name?: string | null } | null;
   132|  };
   133|  const session = value.session?.id && value.session.userId
   134|    ? { id: value.session.id, userId: value.session.userId }
   135|    : null;
   136|  const user = value.user?.id
   137|    ? {
   138|        id: value.user.id,
   139|        email: value.user.email ?? null,
   140|        name: value.user.name ?? null,
   141|      }
   142|    : null;
   143|
   144|  if (!session || !user) return null;
   145|  return { session, user };
   146|}
   147|
   148|export async function resolveBetterAuthSession(
   149|  auth: BetterAuthInstance,
   150|  req: Request,
   151|): Promise<BetterAuthSessionResult | null> {
   152|  return resolveBetterAuthSessionFromHeaders(auth, headersFromExpressRequest(req));
   153|}
