{"content": "     1|import { createHash } from "node:crypto";
     2|import type { IncomingMessage, Server as HttpServer } from "node:http";
     3|import { createRequire } from "node:module";
     4|import type { Duplex } from "node:stream";
     5|import { and, eq, isNull } from "drizzle-orm";
     6|import type { Db } from "@paperclipai/db";
     7|import { agentApiKeys, companyMemberships, instanceUserRoles } from "@paperclipai/db";
     8|import type { DeploymentMode } from "@paperclipai/shared";
     9|import type { BetterAuthSessionResult } from "../auth/better-auth.js";
    10|import { logger } from "../middleware/logger.js";
    11|import { subscribeCompanyLiveEvents } from "../services/live-events.js";
    12|
    13|interface WsSocket {
    14|  readyState: number;
    15|  ping(): void;
    16|  send(data: string): void;
    17|  terminate(): void;
    18|  close(code?: number, reason?: string): void;
    19|  on(event: "pong", listener: () => void): void;
    20|  on(event: "close", listener: () => void): void;
    21|  on(event: "error", listener: (err: Error) => void): void;
    22|}
    23|
    24|interface WsServer {
    25|  clients: Set<WsSocket>;
    26|  on(event: "connection", listener: (socket: WsSocket, req: IncomingMessage) => void): void;
    27|  on(event: "close", listener: () => void): void;
    28|  handleUpgrade(
    29|    req: IncomingMessage,
    30|    socket: Duplex,
    31|    head: Buffer,
    32|    callback: (ws: WsSocket) => void,
    33|  ): void;
    34|  emit(event: "connection", ws: WsSocket, req: IncomingMessage): boolean;
    35|}
    36|
    37|const require = createRequire(import.meta.url);
    38|const { WebSocket, WebSocketServer } = require("ws") as {
    39|  WebSocket: { OPEN: number };
    40|  WebSocketServer: new (opts: { noServer: boolean }) => WsServer;
    41|};
    42|
    43|interface UpgradeContext {
    44|  companyId: string;
    45|  actorType: "board" | "agent";
    46|  actorId: string;
    47|}
    48|
    49|interface IncomingMessageWithContext extends IncomingMessage {
    50|  paperclipUpgradeContext?: UpgradeContext;
    51|}
    52|
    53|function hashToken(token: string) {
    54|  return createHash("sha256").update(token).digest("hex");
    55|}
    56|
    57|function rejectUpgrade(socket: Duplex, statusLine: string, message: string) {
    58|  const safe = message.replace(/[\r\n]+/g, " ").trim();
    59|  socket.write(`HTTP/1.1 ${statusLine}\r\nConnection: close\r\nContent-Type: text/plain\r\n\r\n${safe}`);
    60|  socket.destroy();
    61|}
    62|
    63|function parseCompanyId(pathname: string) {
    64|  const match = pathname.match(/^\/api\/companies\/([^/]+)\/events\/ws$/);
    65|  if (!match) return null;
    66|
    67|  try {
    68|    return decodeURIComponent(match[1] ?? "");
    69|  } catch {
    70|    return null;
    71|  }
    72|}
    73|
    74|function parseBearerToken(rawAuth: string | string[] | undefined) {
    75|  const auth = Array.isArray(rawAuth) ? rawAuth[0] : rawAuth;
    76|  if (!auth) return null;
    77|  if (!auth.toLowerCase().startsWith("bearer ")) return null;
    78|  const token = auth.slice("bearer ".length).trim();
    79|  return token.length > 0 ? token : null;
    80|}
    81|
    82|function headersFromIncomingMessage(req: IncomingMessage): Headers {
    83|  const headers = new Headers();
    84|  for (const [key, raw] of Object.entries(req.headers)) {
    85|    if (!raw) continue;
    86|    if (Array.isArray(raw)) {
    87|      for (const value of raw) headers.append(key, value);
    88|      continue;
    89|    }
    90|    headers.set(key, raw);
    91|  }
    92|  return headers;
    93|}
    94|
    95|async function authorizeUpgrade(
    96|  db: Db,
    97|  req: IncomingMessage,
    98|  companyId: string,
    99|  url: URL,
   100|  opts: {
   101|    deploymentMode: DeploymentMode;
   102|    resolveSessionFromHeaders?: (headers: Headers) => Promise<BetterAuthSessionResult | null>;
   103|  },
   104|): Promise<UpgradeContext | null> {
   105|  const queryToken = url.searchParams.get("token")?.trim() ?? "";
   106|  const authToken = parseBearerToken(req.headers.authorization);
   107|  const token = authToken ?? (queryToken.length > 0 ? queryToken : null);
   108|
   109|  // Browser board context has no bearer token in local_trusted and authenticated modes.
   110|  if (!token) {
   111|    if (opts.deploymentMode === "local_trusted") {
   112|      return {
   113|        companyId,
   114|        actorType: "board",
   115|        actorId: "board",
   116|      };
   117|    }
   118|
   119|    if (opts.deploymentMode !== "authenticated" || !opts.resolveSessionFromHeaders) {
   120|      return null;
   121|    }
   122|
   123|    const session = await opts.resolveSessionFromHeaders(headersFromIncomingMessage(req));
   124|    const userId = session?.user?.id;
   125|    if (!userId) return null;
   126|
   127|    const [roleRow, memberships] = await Promise.all([
   128|      db
   129|        .select({ id: instanceUserRoles.id })
   130|        .from(instanceUserRoles)
   131|        .where(and(eq(instanceUserRoles.userId, userId), eq(instanceUserRoles.role, "instance_admin")))
   132|        .then((rows) => rows[0] ?? null),
   133|      db
   134|        .select({ companyId: companyMemberships.companyId })
   135|        .from(companyMemberships)
   136|        .where(
   137|          and(
   138|            eq(companyMemberships.principalType, "user"),
   139|            eq(companyMemberships.principalId, userId),
   140|            eq(companyMemberships.status, "active"),
   141|          ),
   142|        ),
   143|    ]);
   144|
   145|    const hasCompanyMembership = memberships.some((row) => row.companyId === companyId);
   146|    if (!roleRow && !hasCompanyMembership) return null;
   147|
   148|    return {
   149|      companyId,
   150|      actorType: "board",
   151|      actorId: userId,
   152|    };
   153|  }
   154|
   155|  const tokenHash = hashToken(token);
   156|  const key = await db
   157|    .select()
   158|    .from(agentApiKeys)
   159|    .where(and(eq(agentApiKeys.keyHash, tokenHash), isNull(agentApiKeys.revokedAt)))
   160|    .then((rows) => rows[0] ?? null);
   161|
   162|  if (!key || key.companyId !== companyId) {
   163|    return null;
   164|  }
   165|
   166|  await db
   167|    .update(agentApiKeys)
   168|    .set({ lastUsedAt: new Date() })
   169|    .where(eq(agentApiKeys.id, key.id));
   170|
   171|  return {
   172|    companyId,
   173|    actorType: "agent",
   174|    actorId: key.agentId,
   175|  };
   176|}
   177|
   178|export function setupLiveEventsWebSocketServer(
   179|  server: HttpServer,
   180|  db: Db,
   181|  opts: {
   182|    deploymentMode: DeploymentMode;
   183|    resolveSessionFromHeaders?: (headers: Headers) => Promise<BetterAuthSessionResult | null>;
   184|  },
   185|) {
   186|  const wss = new WebSocketServer({ noServer: true });
   187|  const cleanupByClient = new Map<WsSocket, () => void>();
   188|  const aliveByClient = new Map<WsSocket, boolean>();
   189|
   190|  const pingInterval = setInterval(() => {
   191|    for (const socket of wss.clients) {
   192|      if (!aliveByClient.get(socket)) {
   193|        socket.terminate();
   194|        continue;
   195|      }
   196|      aliveByClient.set(socket, false);
   197|      socket.ping();
   198|    }
   199|  }, 30000);
   200|
   201|  wss.on("connection", (socket: WsSocket, req: IncomingMessage) => {
   202|    const context = (req as IncomingMessageWithContext).paperclipUpgradeContext;
   203|    if (!context) {
   204|      socket.close(1008, "missing context");
   205|      return;
   206|    }
   207|
   208|    const unsubscribe = subscribeCompanyLiveEvents(context.companyId, (event) => {
   209|      if (socket.readyState !== WebSocket.OPEN) return;
   210|      socket.send(JSON.stringify(event));
   211|    });
   212|
   213|    cleanupByClient.set(socket, unsubscribe);
   214|    aliveByClient.set(socket, true);
   215|
   216|    socket.on("pong", () => {
   217|      aliveByClient.set(socket, true);
   218|    });
   219|
   220|    socket.on("close", () => {
   221|      const cleanup = cleanupByClient.get(socket);
   222|      if (cleanup) cleanup();
   223|      cleanupByClient.delete(socket);
   224|      aliveByClient.delete(socket);
   225|    });
   226|
   227|    socket.on("error", (err: Error) => {
   228|      logger.warn({ err, companyId: context.companyId }, "live websocket client error");
   229|    });
   230|  });
   231|
   232|  wss.on("close", () => {
   233|    clearInterval(pingInterval);
   234|  });
   235|
   236|  server.on("upgrade", (req, socket, head) => {
   237|    if (!req.url) {
   238|      rejectUpgrade(socket, "400 Bad Request", "missing url");
   239|      return;
   240|    }
   241|
   242|    const url = new URL(req.url, "http://localhost");
   243|    const companyId = parseCompanyId(url.pathname);
   244|    if (!companyId) {
   245|      socket.destroy();
   246|      return;
   247|    }
   248|
   249|    void authorizeUpgrade(db, req, companyId, url, {
   250|      deploymentMode: opts.deploymentMode,
   251|      resolveSessionFromHeaders: opts.resolveSessionFromHeaders,
   252|    })
   253|      .then((context) => {
   254|        if (!context) {
   255|          rejectUpgrade(socket, "403 Forbidden", "forbidden");
   256|          return;
   257|        }
   258|
   259|        const reqWithContext = req as IncomingMessageWithContext;
   260|        reqWithContext.paperclipUpgradeContext = context;
   261|
   262|        wss.handleUpgrade(req, socket, head, (ws: WsSocket) => {
   263|          wss.emit("connection", ws, reqWithContext);
   264|        });
   265|      })
   266|      .catch((err) => {
   267|        logger.error({ err, path: req.url }, "failed websocket upgrade authorization");
   268|        rejectUpgrade(socket, "500 Internal Server Error", "upgrade failed");
   269|      });
   270|  });
   271|
   272|  return wss;
   273|}
